task_name = alert.get('task_name', '')
task_action = alert.get('task_action', '')
creator = alert.get('creator', '')
run_level = alert.get('run_level', 'user')
flags = []
if run_level.lower() in ['system', 'highest']:
    flags.append('system_level')
if '-enc' in task_action.lower() or 'encodedcommand' in task_action.lower():
    flags.append('encoded_payload')
if 'hidden' in alert.get('task_settings', '').lower():
    flags.append('hidden_task')
if any(x in task_action.lower() for x in ['powershell', 'cmd.exe', 'mshta', 'wscript', 'cscript', 'rundll32']):
    flags.append('suspicious_binary')
result = {'task_name': task_name, 'flags': flags, 'flag_count': len(flags), 'suspicious': len(flags) >= 1, 'run_level': run_level, 'creator': creator}

